<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">NAVIGATION RULES</span><h1>Symptoms and Department Rules</h1><p>Rules support hospital navigation only and must never state a diagnosis.</p></div></div><form class="admin-panel admin-form" method="post" action="<?=url('admin/ai-symptoms')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($editing['id']??'')?>"><div class="form-grid"><label>English symptom label<input name="name_en" value="<?=e($editing['name_en']??'')?>" required></label><label>বাংলা লক্ষণ<input name="name_bn" value="<?=e($editing['name_bn']??'')?>"></label><label class="full">English keywords<input name="keywords_en" value="<?=e($editing['keywords_en']??'')?>" required></label><label class="full">বাংলা কীওয়ার্ড<input name="keywords_bn" value="<?=e($editing['keywords_bn']??'')?>"></label><label><span class="toggle"><input id="emergency-rule" type="checkbox" name="is_emergency" value="1" <?=!empty($editing['is_emergency'])?'checked':''?>> Emergency warning rule</span></label><label><span class="toggle"><input type="checkbox" name="is_active" value="1" <?=!isset($editing['is_active'])||$editing['is_active']?'checked':''?>> Active</span></label><label class="full">Emergency message — English<textarea name="emergency_message_en" rows="3"><?=e($editing['emergency_message_en']??'')?></textarea></label><label class="full">জরুরি বার্তা — বাংলা<textarea name="emergency_message_bn" rows="3"><?=e($editing['emergency_message_bn']??'')?></textarea></label><label>Recommended department<select name="department_id"><option value="">None for emergency rules</option><?php foreach($departments as$d):?><option value="<?=$d['id']?>" <?=($editing['department_id']??'')==$d['id']?'selected':''?>><?=e($d['name'])?></option><?php endforeach;?></select></label><label>Rule priority<input type="number" name="priority" value="<?=e($editing['priority']??10)?>"></label><label class="full">Navigation recommendation — English<textarea name="recommendation_en" rows="3"><?=e($editing['recommendation_en']??'This department may be appropriate. This is not a diagnosis.')?></textarea></label><label class="full">বিভাগের পরামর্শ — বাংলা<textarea name="recommendation_bn" rows="3"><?=e($editing['recommendation_bn']??'এই বিভাগটি উপযুক্ত হতে পারে। এটি রোগ নির্ণয় নয়।')?></textarea></label></div><button class="btn"><?=$editing?'Update':'Add'?> Rule</button></form><div class="admin-panel"><div class="table-wrap"><table><thead><tr><th>Symptom</th><th>বাংলা</th><th>Type</th><th>Department</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as$x):?><tr><td><?=e($x['name_en'])?></td><td><?=e($x['name_bn'])?></td><td><span class="status-pill <?=$x['is_emergency']?'cancelled':'confirmed'?>"><?=$x['is_emergency']?'Emergency':'Navigation'?></span></td><td><?=e($x['departments'])?></td><td><?=$x['is_active']?'Active':'Inactive'?></td><td><a class="btn small outline" href="<?=url('admin/ai-symptoms?id='.$x['id'])?>">Edit</a></td></tr><?php endforeach;?></tbody></table></div></div></div></section>

